"use client";

import React, { useEffect, useRef } from "react";
import { Input } from "../ui/input.tsx";

import type {
  Cell,
  Column,
  Row,
  Table,
  TableMeta,
} from "@tanstack/react-table";
import { useSpreadsheetStore } from "../lib/spreadsheet-store";

interface SpreadsheetRow {
  id: string;
  [key: string]: unknown;
}

interface SpreadsheetTableMeta<TData extends SpreadsheetRow>
  extends TableMeta<TData> {
  updateData?: (rowIndex: number, columnId: string, value: unknown) => void;
}

interface EditableCellProps<TData extends SpreadsheetRow = SpreadsheetRow> {
  getValue: () => unknown;
  row: Row<TData>;
  column: Column<TData, unknown>;
  table: Table<TData>;
}

export const EditableCell = <TData extends SpreadsheetRow = SpreadsheetRow>({
  getValue,
  row,
  column,
  table,
}: EditableCellProps<TData>) => {
  const editingCell = useSpreadsheetStore((state) => state.editingCell);
  const setEditingCell = useSpreadsheetStore((state) => state.setEditingCell);
  const updateData = useSpreadsheetStore((state) => state.updateData);
  const value = getValue() as string;
  const isEditing =
    editingCell?.rowId === row.original.id &&
    editingCell?.columnId === column.id;

  const onChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    updateData(row.original.id, column.id, e.target.value);
  };

  const onBlur = () => {
    setEditingCell(null);
  };

  const onKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "Enter" || e.key === "Escape") {
      setEditingCell(null);
    }
    e.stopPropagation();
  };

  if (isEditing) {
    return (
      <Input
        value={value}
        onChange={onChange}
        onBlur={onBlur}
        onKeyDown={onKeyDown}
        className="h-8 w-full rounded-none border-0 bg-transparent p-1 text-sm focus-visible:ring-blue-600/20 dark:focus-visible:ring-blue-400/30"
        autoFocus
      />
    );
  }

  return (
    <div className="h-8 w-full p-1">
      <span className="text-foreground block truncate text-sm" title={value}>
        {value}
      </span>
    </div>
  );
};

"use client";

import React from "react";
import { cn } from "../ui/utils.tsx";
import { flexRender } from "@tanstack/react-table";

import type { SpreadsheetRow } from "../lib/spreadsheet-store";
import type { Table } from "@tanstack/react-table";
import type { VirtualItem } from "@tanstack/react-virtual";

interface MemoizedTableBodyProps<TRow extends SpreadsheetRow> {
  virtualItems: VirtualItem[];
  table: Table<TRow>;
  selectedCells: Set<string>;
  getRowCells: (rowId: string) => string[];
  handleMouseDown: (
    e: React.MouseEvent,
    rowId: string,
    columnId: string,
  ) => void;
  handleMouseMove: (
    e: React.MouseEvent,
    rowId: string,
    columnId: string,
  ) => void;
  showRowNumbers?: boolean;
  renderRowNumber?: (rowIndex: number) => React.ReactNode;
  renderRowActions?: (row: TRow, rowIndex: number) => React.ReactNode;
}

function MemoizedTableBodyInner<TRow extends SpreadsheetRow>({
  virtualItems,
  table,
  selectedCells,
  getRowCells,
  handleMouseDown,
  handleMouseMove,
  showRowNumbers = true,
  renderRowNumber,
  renderRowActions,
}: MemoizedTableBodyProps<TRow>) {
  return (
    <>
      {virtualItems.map((virtualRow) => {
        const row = table.getRowModel().rows[virtualRow.index];
        const rowIndex = virtualRow.index;
        const rowId = row?.original?.id;
        if (!rowId) return null;

        const rowCells = getRowCells(rowId);
        const isRowSelected = rowCells.every((cell) => selectedCells.has(cell));

        return (
          <div
            key={row.id}
            className={cn(
              "hover:bg-muted/30 dark:hover:bg-muted/20 absolute top-0 left-0 w-full transition-colors",
              isRowSelected && "bg-muted/50 dark:bg-muted/40",
            )}
            style={{
              height: `${virtualRow.size}px`,
              transform: `translateY(${virtualRow.start}px)`,
            }}
          >
            <div className="flex h-full">
              {/* Row number */}
              {showRowNumbers && (
                <div
                  data-row-number
                  className={cn(
                    "border-border bg-muted/30 text-muted-foreground hover:bg-muted/50 dark:hover:bg-muted/40 flex h-9 w-12 shrink-0 cursor-default items-center justify-center border-r border-b font-mono text-xs transition-colors",
                    isRowSelected && "bg-muted dark:bg-muted/80",
                  )}
                  onMouseDown={(e) => handleMouseDown(e, rowId, "")}
                  onMouseMove={(e) => handleMouseMove(e, rowId, "")}
                >
                  {renderRowNumber ? renderRowNumber(rowIndex) : rowIndex + 1}
                </div>
              )}
              {row.getVisibleCells().map((cell) => {
                const cellKey = `${rowId}:${cell.column.id}`;
                const isCellSelected = selectedCells.has(cellKey);

                return (
                  <div
                    key={cell.id}
                    className={cn(
                      "border-border relative flex h-9 shrink-0 cursor-default items-center border-r border-b transition-colors",
                      isCellSelected && "bg-blue-50 dark:bg-blue-950/50",
                    )}
                    style={{
                      width: `calc(var(--col-${cell.column.id}-size) * 1px)`,
                    }}
                    onMouseDown={(e) =>
                      handleMouseDown(e, rowId, cell.column.id)
                    }
                    onMouseMove={(e) =>
                      handleMouseMove(e, rowId, cell.column.id)
                    }
                  >
                    {flexRender(cell.column.columnDef.cell, cell.getContext())}
                  </div>
                );
              })}
              {/* Row actions */}
              {renderRowActions && (
                <div className="border-border flex h-9 shrink-0 items-center justify-center border-b">
                  {renderRowActions(row.original, rowIndex)}
                </div>
              )}
            </div>
          </div>
        );
      })}
    </>
  );
}

export const MemoizedTableBody = React.memo(
  MemoizedTableBodyInner,
  (prevProps, nextProps) => {
    return (
      prevProps.virtualItems === nextProps.virtualItems &&
      prevProps.selectedCells === nextProps.selectedCells &&
      prevProps.getRowCells === nextProps.getRowCells &&
      prevProps.handleMouseDown === nextProps.handleMouseDown &&
      prevProps.handleMouseMove === nextProps.handleMouseMove
    );
  },
) as <TRow extends SpreadsheetRow>(
  props: MemoizedTableBodyProps<TRow>,
) => React.ReactElement;

MemoizedTableBodyInner.displayName = "MemoizedTableBodyInner";

"use client";

import React, { useRef, useState } from "react";
import { cn } from "../ui/utils.tsx";

interface ResizeHandleProps {
  columnId: string;
  columnWidths: Record<string, number>;
  handleColumnResize: (columnId: string, width: number) => void;
  tableContainerRef: React.RefObject<HTMLDivElement | null>;
  dragLineRef: React.RefObject<HTMLDivElement | null>;
  setDragLineVisible: (visible: boolean) => void;
  className?: string;
}

export const ResizeHandle = React.forwardRef<HTMLDivElement, ResizeHandleProps>(
  (
    {
      columnId,
      columnWidths,
      handleColumnResize,
      tableContainerRef,
      dragLineRef,
      setDragLineVisible,
      className,
    },
    ref,
  ) => {
    const [isResizing, setIsResizing] = useState(false);
    const startXRef = useRef(0);
    const startWidthRef = useRef(0);
    const columnStartXRef = useRef(0);
    const currentMouseXRef = useRef(0);

    const handleMouseDown = (e: React.MouseEvent) => {
      e.preventDefault();
      e.stopPropagation();
      setIsResizing(true);
      setDragLineVisible(true);
      startXRef.current = e.clientX;
      startWidthRef.current = columnWidths[columnId];

      const headerElement = e.currentTarget.closest(
        "[data-column-id]",
      ) as HTMLElement;
      if (headerElement) {
        const rect = headerElement.getBoundingClientRect();
        const tableRect = tableContainerRef.current?.getBoundingClientRect();
        if (tableRect) {
          columnStartXRef.current = rect.left - tableRect.left;
          const initialDragX =
            columnStartXRef.current + startWidthRef.current - 2; // -2px to center on the 4px wide handle
          if (dragLineRef.current) {
            dragLineRef.current.style.left = `${initialDragX}px`;
          }
        }
      }

      const handleMouseMove = (e: MouseEvent) => {
        currentMouseXRef.current = e.clientX;
        const deltaX = e.clientX - startXRef.current;
        const newWidth = Math.max(60, startWidthRef.current + deltaX);
        const dragX = columnStartXRef.current + newWidth - 2; // Keep drag line centered on resize handle position

        if (dragLineRef.current) {
          dragLineRef.current.style.left = `${dragX}px`;
        }
      };

      const handleMouseUp = () => {
        setIsResizing(false);
        setDragLineVisible(false);
        const deltaX = currentMouseXRef.current - startXRef.current;
        const newWidth = Math.max(60, startWidthRef.current + deltaX);
        handleColumnResize(columnId, newWidth);
        document.removeEventListener("mousemove", handleMouseMove);
        document.removeEventListener("mouseup", handleMouseUp);
      };

      document.addEventListener("mousemove", handleMouseMove);
      document.addEventListener("mouseup", handleMouseUp);
    };

    return (
      <div
        ref={ref}
        className={cn(
          "hover:bg-primary/50 dark:hover:bg-primary/60 absolute top-0 right-0 h-full w-1 cursor-col-resize transition-colors",
          isResizing && "bg-primary dark:bg-primary/80",
          className,
        )}
        onMouseDown={handleMouseDown}
      />
    );
  },
);

ResizeHandle.displayName = "ResizeHandle";

"use client";

import React, { useCallback, useEffect, useMemo, useRef } from "react";
import { cn } from "../ui/utils.tsx";
import {
  flexRender,
  getCoreRowModel,
  useReactTable,
} from "@tanstack/react-table";
import { useVirtualizer } from "@tanstack/react-virtual";

import type { SpreadsheetRow } from "../lib/spreadsheet-store";
import type { ColumnInfo } from "../lib/spreadsheet-utils";
import type { ColumnDef } from "@tanstack/react-table";
import { useSpreadsheetStore } from "../lib/spreadsheet-store";
import {
  createNavigationMap,
  getColumnSizeVars,
  getRowCells,
} from "../lib/spreadsheet-utils";
import { useSpreadsheetHandlers } from "../lib/use-spreadsheet-handlers";
import { MemoizedTableBody } from "./memoized-table-body";
import { ResizeHandle } from "./resize-handle";

interface SpreadsheetProps<TRow extends SpreadsheetRow, TValue = unknown>
  extends React.HTMLAttributes<HTMLDivElement> {
  columns: ColumnDef<TRow, TValue>[];
  showRowNumbers?: boolean;
  renderRowNumber?: (rowIndex: number) => React.ReactNode;
  renderRowActions?: (row: TRow, rowIndex: number) => React.ReactNode;
}

function SpreadsheetInner<TRow extends SpreadsheetRow, TValue = unknown>(
  {
    className,
    style,
    columns,
    showRowNumbers = true,
    renderRowNumber,
    renderRowActions,
    ...props
  }: SpreadsheetProps<TRow, TValue>,
  ref: React.Ref<HTMLDivElement>,
) {
  const data = useSpreadsheetStore((state) => state.data);
  const selectedCells = useSpreadsheetStore((state) => state.selectedCells);
  const isDragging = useSpreadsheetStore((state) => state.isDragging);
  const columnWidths = useSpreadsheetStore((state) => state.columnWidths);
  const setColumnWidths = useSpreadsheetStore((state) => state.setColumnWidths);
  const deleteRow = useSpreadsheetStore((state) => state.deleteRow);
  const dragLineVisible = useSpreadsheetStore((state) => state.dragLineVisible);
  const setDragLineVisible = useSpreadsheetStore(
    (state) => state.setDragLineVisible,
  );

  const tableContainerRef = useRef<HTMLDivElement>(null);
  const dragLineRef = useRef<HTMLDivElement>(null);

  const table = useReactTable({
    data: data as TRow[],
    columns,
    getCoreRowModel: getCoreRowModel(),
  });

  // Compute column meta locally - no need to store in Zustand
  const columnMeta = useMemo<ColumnInfo[]>(() => {
    return table.getAllLeafColumns().map((column) => ({
      id: column.id,
      accessorKey:
        typeof (column.columnDef as any).accessorKey === "string"
          ? (column.columnDef as any).accessorKey
          : column.id,
    }));
  }, [table]);

  // Compute navigation map locally - no need to store in Zustand
  const navigationMap = useMemo(() => {
    if (columnMeta.length > 0) {
      return createNavigationMap(data, columnMeta);
    }
    return new Map();
  }, [data, columnMeta]);

  const columnSizeVars = useMemo(
    () => getColumnSizeVars(columnWidths),
    [columnWidths],
  );

  const { handleMouseDown, handleMouseMove, handleMouseUp, handleKeyDown } =
    useSpreadsheetHandlers({
      columns: columnMeta,
      navigationMap,
    });

  const handleColumnResize = useCallback(
    (columnId: string, width: number) => {
      setColumnWidths((prev) => ({
        ...prev,
        [columnId]: Math.max(60, width),
      }));
    },
    [setColumnWidths],
  );

  const getRowCellsHelper = useCallback(
    (rowId: string) => {
      return getRowCells(rowId, columnMeta);
    },
    [columnMeta],
  );

  // Mouseup should be global to handle drag ending outside the spreadsheet
  useEffect(() => {
    const handleGlobalMouseUp = () => {
      handleMouseUp();
    };

    document.addEventListener("mouseup", handleGlobalMouseUp);
    return () => {
      document.removeEventListener("mouseup", handleGlobalMouseUp);
    };
  }, [handleMouseUp]);

  const rowVirtualizer = useVirtualizer({
    count: table.getRowModel().rows.length,
    getScrollElement: () => tableContainerRef.current,
    estimateSize: () => 36,
    overscan: 10,
  });

  return (
    <div
      ref={ref}
      className={cn(
        "relative flex flex-col",
        isDragging && "select-none",
        className,
      )}
      style={{ ...columnSizeVars, ...style }}
      tabIndex={0}
      onKeyDown={handleKeyDown}
      {...props}
    >
      <div
        ref={dragLineRef}
        className={cn(
          "bg-primary pointer-events-none absolute top-0 bottom-0 z-50 w-0.5 transition-opacity",
          dragLineVisible ? "opacity-100" : "opacity-0",
        )}
      />

      <div className="bg-muted border-border sticky top-0 z-1 flex border-y">
        {showRowNumbers && (
          <div className="border-border bg-muted text-muted-foreground flex h-10 w-12 shrink-0 items-center justify-center border-r text-xs font-medium">
            #
          </div>
        )}
        {table.getHeaderGroups()[0].headers.map((header) => (
          <div
            key={header.id}
            data-column-id={header.column.id}
            data-column-header
            className="border-border bg-muted text-muted-foreground relative flex h-10 shrink-0 cursor-default items-center border-r pl-1 text-left text-xs font-medium transition-colors"
            style={{
              width: `calc(var(--col-${header.column.id}-size) * 1px)`,
            }}
            onMouseDown={(e) => handleMouseDown(e, "", header.column.id)}
            onMouseMove={(e) => handleMouseMove(e, "", header.column.id)}
          >
            {header.isPlaceholder
              ? null
              : flexRender(header.column.columnDef.header, header.getContext())}
            <ResizeHandle
              columnId={header.column.id}
              columnWidths={columnWidths}
              handleColumnResize={handleColumnResize}
              tableContainerRef={tableContainerRef}
              dragLineRef={dragLineRef}
              setDragLineVisible={setDragLineVisible}
            />
          </div>
        ))}
        {showRowNumbers && (
          <div className="border-border bg-muted text-muted-foreground flex h-10 w-12 shrink-0 items-center justify-center border-r text-xs font-medium" />
        )}
      </div>

      <div ref={tableContainerRef} className="flex-1">
        <div
          style={{
            height: `${rowVirtualizer.getTotalSize()}px`,
            position: "relative",
          }}
        >
          <MemoizedTableBody
            virtualItems={rowVirtualizer.getVirtualItems()}
            table={table}
            selectedCells={selectedCells}
            getRowCells={getRowCellsHelper}
            handleMouseDown={handleMouseDown}
            handleMouseMove={handleMouseMove}
            showRowNumbers={showRowNumbers}
            renderRowNumber={renderRowNumber}
            renderRowActions={renderRowActions}
          />
        </div>
      </div>
    </div>
  );
}

SpreadsheetInner.displayName = "SpreadsheetInner";

export const Spreadsheet = React.forwardRef(SpreadsheetInner) as <
  TRow extends SpreadsheetRow,
  TValue = unknown,
>(
  props: SpreadsheetProps<TRow, TValue> & { ref?: React.Ref<HTMLDivElement> },
) => React.ReactElement;

(Spreadsheet as unknown as { displayName: string }).displayName = "Spreadsheet";

"use client";

import React from "react";
import { cn } from "../ui/utils.tsx";

import { useSpreadsheetStore } from "../lib/spreadsheet-store";

export interface StatusBarProps extends React.HTMLAttributes<HTMLDivElement> {
  children?: React.ReactNode;
}

export const StatusBar = React.forwardRef<HTMLDivElement, StatusBarProps>(
  ({ children, className, ...props }, ref) => (
    <div
      ref={ref}
      className={cn(
        "text-muted-foreground bg-background dark:bg-background/95 sticky bottom-0 flex items-center justify-between border-t p-2 text-xs",
        className,
      )}
      {...props}
    >
      {children}
    </div>
  ),
);
StatusBar.displayName = "StatusBar";

interface StatusBarSectionProps extends React.HTMLAttributes<HTMLDivElement> {}

export const StatusBarSection = React.forwardRef<
  HTMLDivElement,
  StatusBarSectionProps
>(({ className, ...props }, ref) => (
  <div
    ref={ref}
    className={cn("flex flex-1 items-center gap-2", className)}
    {...props}
  />
));
StatusBarSection.displayName = "StatusBarSection";

export const StatusBarMessage: React.FC = () => {
  const editingCell = useSpreadsheetStore((state) => state.editingCell);
  const selectedCells = useSpreadsheetStore((state) => state.selectedCells);
  const data = useSpreadsheetStore((state) => state.data);
  const selectedCellsCount = selectedCells.size;

  if (editingCell) {
    const rowIndex = data.findIndex((row) => row.id === editingCell.rowId);
    const displayRowNumber = rowIndex !== -1 ? rowIndex + 1 : "?";

    return (
      <span>
        Editing row {displayRowNumber}, column {editingCell.columnId}
      </span>
    );
  }

  if (selectedCellsCount > 0) {
    return (
      <span>
        Selected: {selectedCellsCount} cell
        {selectedCellsCount > 1 ? "s" : ""}
      </span>
    );
  }

  return <span>Click a cell to select</span>;
};

export const StatusBarSummary: React.FC = () => {
  const data = useSpreadsheetStore((state) => state.data);
  const rowCount = data.length;

  return (
    <span>
      {rowCount} rows × {data[0]?.length} columns
    </span>
  );
};

"use client";

import React from "react";
import { Button } from "../ui/button.tsx";
import { cn } from "../ui/utils.tsx";

export interface ToolbarProps extends React.HTMLAttributes<HTMLDivElement> {
  children?: React.ReactNode;
}

export const Toolbar = React.forwardRef<HTMLDivElement, ToolbarProps>(
